  ('locality-d0d1b9a2-moex-00474', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'essay', '甲公司於 X7 年1 月 1 日以繼續留在公司服務滿3 年為條件，給與總
經理一項權利，可選擇收取相當於 50,000 股普通股市價的現金，或
收取 60,000股、面額$10的股票。總經理若選擇取得股票，則於既得
日後 2 年內均不得出售。X7 年初給與日甲公司之股價為$48，X7、
X8、X9 年底股價分別為$52、$54 及$58。考慮既得後移轉限制之影
響，甲公司估計給與日選擇股票之公允價值為每股$42。
試作：
計算甲公司 X7 年至 X9 年各年度應認列的薪資費用。（6分）
若 X9 年底總經理選擇領取現金，作甲公司之分錄。（3分）
若 X9 年底總經理選擇領取股票，作甲公司之分錄。（3分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00475', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '臺北公司 2021 年有以下事件，⑴當年發生訴訟案件導致損失$25,000、⑵處分停業部門導致 損失$50,000、⑶會計人員發現2019年的存貨低估$20,000、⑷會計人員發現2019年折舊費用 高估$10,000。該公司所得稅率為40%，試計算以上事件影響2021年繼續營業部門稅後淨利 數額。', '["減少$15,000", "減少$45,000", "減少$27,000", "增加$3,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00476', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列期後事項，何者不需要調整財務報表？', '["在報導期間結束日後，通過發布財務報表日之前，發生專利權糾紛被合作廠商控告侵權， 公司預估敗訴之可能性相當高", "在報導期間結束日後之存貨銷貨價格，可能提供該存貨於報導期間結束日的淨變現價值之 佐證", "在報導期間結束日後，通過發布財務報表日之前，重要客戶因長期財務狀況惡化而宣布破 產，導致公司有大筆應收帳款無法收回", "截至報導期間結束日之所得稅申報因某項疑義，造成最後國稅局核定的所得稅額較原先的 估計數高出許多"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00477', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '高雄公司之現金管理符合內控原則，其收款及付款皆透過支票，相關資料如下： 銀行調節表 5月31日 銀行帳上餘額 $30,286 加：在途存款 4,900 減：未兌現支票 (3,700) 公司帳上餘額 $31,486 6月份相關資料如下 銀行 公司 6月30日餘額 $25,940 ？ 6月份存款 10,423 13,458 6月份付款 11,800 10,480 6月份代收票據 2,500 6月份銀行手續費 60 6月份存款不足支票 1,000 請計算6月30日銀行調節表之正確現金餘額。', '["$39,398", "$34,464", "$36,904", "$31,495"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00478', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$1,000,000購置自用土地一筆，採用成本模式衡量。X3年初決定將該閒 置土地轉換為採用公允價值模式之投資性不動產。 甲公司對於土地若於 X1 年初採用重估價模式衡量，X1 年底重估價，土地公允價值為 $950,000，X2年底重估價，土地公允價值為$1,100,000，X3年底土地之公允價值為$1,500,000。 則對甲公司X2年度及X3年度綜合損益表之影響，下列何者正確？（不考慮所得稅影響數）', '["X2年度淨利增加$50,000，其他綜合損益增加$100,000", "X2年度淨利無差異，其他綜合損益增加$150,000", "X3年度淨利無差異，其他綜合損益增加$100,000", "X3年度淨利無差異，其他綜合損益無差異"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00479', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '八里公司不幸於2020年年底發生火災，倉庫存貨全部燒毀，會計人員立即協助提供2020年 度相關資料：期初存貨$158,350，全年進貨成本$267,000，全年銷貨收入為$500,000，會計人 員依過去三年平均毛利率估計存貨火災損失$100,350，試計算八里公司過去三年平均毛利率。', '["15%", "20%", "35%", "65%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00480', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲農場栽種供未來取得製成果醬出售之蘋果樹，於X1年初以$100,000購入蘋果樹10株，另 支付運費$8,000 將該蘋果樹由市場運回農場栽種。甲農場估計若同日立即處分該 10 株蘋果 樹，除了需要支付運費$8,000 將其運回市場外，並另需支付經銷商佣金等出售成本$2,000。 試問甲農場X1年初應認列生物資產之金額為何？', '["$90,000", "$100,000", "$108,000", "$110,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00481', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '承上題，若甲農場內有部分蘋果樹是供未來採收蘋果以出售。X1年11月採收蘋果100公斤， X1年底皆尚未出售。採收時蘋果每公斤市場報價為$52，X1年底蘋果每公斤市場報價為$55。 甲農場估計若將採收蘋果運至果菜拍賣市場交易，需要支付運費每公斤$3，並另需支付交易 規費每公斤$2。試問甲農場X1年12月31日應認列該採收之蘋果存貨之金額為何？', '["$4,700", "$5,000", "$5,200", "$5,700"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00482', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$973,270購入面額$1,000,000三年期的公司債，票面利率5%，市 場有效利率6%，每年年底付息。甲公司對該債券投資分類為透過其他綜合損益按公允價值衡 量之債券投資。X1年12月31日該公司債之市場利率為4%，當時該公司債之信用評等為投 資等級，其12個月預期違約率為1%，違約損失率為20%，而存續期間之預期違約率為2%， 違約損失率為30%。試問甲公司X1年12月31日應認列之減損損失金額為何？（金額四捨 五入至整數）', '["$1,947", "$1,963", "$5,890", "$6,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00483', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '承上題，X1年12月31日決定改變其管理債券的經營模式，即自透過其他綜合損益按公允價 值衡量重分類至透過損益按公允價值衡量。下列關於重分類所應認列之重分類損益金額，何 者正確？（金額四捨五入至整數）', '["無重分類損益", "重分類損失$18,334", "重分類利益$37,195", "重分類利益$39,158"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
